SELECT player_name
FROM players
WHERE contract_end_date = '2022-2023';

SELECT AVG(p.salary) AS average_salary
FROM players p
WHERE p.draft_year = (
  SELECT MAX(draft_year)
  FROM players
) AND p.team = (
  SELECT s.champion_team
  FROM seasons s
  WHERE s.season_id = (
    SELECT MAX(season_id)
    FROM seasons
  )
);

SELECT AVG(salary) AS average_salary
FROM players
WHERE contract_end_date = '2022-2023';

SELECT s.season_name, p.draft_year
FROM seasons s, players p
ORDER BY s.season_name, p.draft_year;
